import{_ as t,C as i,o as a,c as n,a3 as d,b as c,w as o,a as l,E as s,a4 as m}from"./chunks/framework.aYYe0dfI.js";const x=JSON.parse('{"title":"Module generate:diagram","description":"The generate:diagram module provides a suite of functions for producing diagram code—primarily in Mermaid syntax—that visualises various structural and dependency relationships within a project. Its public API includes renderers for file dependency graphs, import diagrams, namespace structures, and module dependency diagrams, as well as a utility to escape labels for safe embedding in Mermaid output and a guard function (should_emit_mermaid) that determines whether a diagram should be emitted based on thresholds like minimum node or edge counts. The module owns all logic for traversing the extracted project model, collecting relevant symbols, and formatting the diagram text, while relying on the config, extract, and generate:model modules for configuration, data extraction, and page plan context.","frontmatter":{"title":"Module generate:diagram","description":"The generate:diagram module provides a suite of functions for producing diagram code—primarily in Mermaid syntax—that visualises various structural and dependency relationships within a project. Its public API includes renderers for file dependency graphs, import diagrams, namespace structures, and module dependency diagrams, as well as a utility to escape labels for safe embedding in Mermaid output and a guard function (should_emit_mermaid) that determines whether a diagram should be emitted based on thresholds like minimum node or edge counts. The module owns all logic for traversing the extracted project model, collecting relevant symbols, and formatting the diagram text, while relying on the config, extract, and generate:model modules for configuration, data extraction, and page plan context.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/generate/diagram.md","filePath":"en/clore/modules/generate/diagram.md"}'),h={name:"clore/modules/generate/diagram.md"};function u(p,e,g,f,_,b){const r=i("Mermaid");return a(),n("div",null,[e[1]||(e[1]=d('<h1 id="module-generate-diagram" tabindex="-1">Module <code>generate:diagram</code> <a class="header-anchor" href="#module-generate-diagram" aria-label="Permalink to &quot;Module `generate:diagram`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>generate:diagram</code> module provides a suite of functions for producing diagram code—primarily in Mermaid syntax—that visualises various structural and dependency relationships within a project. Its public API includes renderers for file dependency graphs, import diagrams, namespace structures, and module dependency diagrams, as well as a utility to escape labels for safe embedding in Mermaid output and a guard function (<code>should_emit_mermaid</code>) that determines whether a diagram should be emitted based on thresholds like minimum node or edge counts. The module owns all logic for traversing the extracted project model, collecting relevant symbols, and formatting the diagram text, while relying on the <code>config</code>, <code>extract</code>, and <code>generate:model</code> modules for configuration, data extraction, and page plan context.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./model"><code>generate:model</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./scheduler"><code>generate:scheduler</code></a></li><li><a href="./symbol"><code>generate:symbol</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',8)),(a(),c(m,null,{default:o(()=>[s(r,{id:"mermaid-57",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22generate%22%5D%0A%20%20%20%20I0%5B%22config%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22extract%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22support%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=d('<h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-escape-mermaid-label" tabindex="-1"><code>clore::generate::escape_mermaid_label</code> <a class="header-anchor" href="#clore-generate-escape-mermaid-label" aria-label="Permalink to &quot;`clore::generate::escape_mermaid_label`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:13</code></p><p>Definition: <code>generate/render/diagram.cppm:109</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function iterates over each character in the input <code>text</code>, using a <code>switch</code> to handle four categories. Backslash and double quote are each escaped by prefixing with a backslash, ensuring that the output remains syntactically valid within Mermaid quoted strings. Newline and carriage return characters are replaced with a space, since Mermaid labels cannot contain line breaks; all other characters are copied unchanged. The return value is built into a local <code>std::string escaped</code> whose capacity is pre‑reserved to <code>text.size()</code> to avoid reallocation. The only dependencies are <code>std::string_view</code> (the input parameter) and <code>std::string</code> (the return type), and no helper functions from the enclosing namespace are invoked.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>text</code> parameter</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value (new <code>std::string</code>)</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used when generating Mermaid diagram code to ensure labels are properly formatted and do not break the diagram syntax.</li></ul><h3 id="clore-generate-render-file-dependency-diagram-code" tabindex="-1"><code>clore::generate::render_file_dependency_diagram_code</code> <a class="header-anchor" href="#clore-generate-render-file-dependency-diagram-code" aria-label="Permalink to &quot;`clore::generate::render_file_dependency_diagram_code`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:20</code></p><p>Definition: <code>generate/render/diagram.cppm:222</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function first checks whether <code>plan.owner_keys</code> is empty and returns an empty string if so. It then delegates the main work to <code>render_cached_diagram</code>, which wraps the actual generation. Inside the lambda, it attempts to locate the file record from <code>model.files</code> using the first owner key; if the file is not found, the diagram is skipped. The algorithm then builds a sorted, deduplicated list of include labels by iterating over the file’s <code>includes</code> and calling <code>make_source_relative</code> to produce paths relative to the project root. Next, it invokes <code>collect_implementation_symbols_for_diagram</code> with a predicate that selects symbols of type, local variable, or function kinds. The total <code>edge_count</code> is computed as the sum of the number of includes and the number of symbols, and <code>node_count</code> is set to <code>1 + edge_count</code>. If <code>should_emit_mermaid</code> returns <code>false</code> (typically when the diagram would be too small or too large), an empty string is returned immediately.</p><p>Otherwise, the function constructs a Mermaid <code>graph LR</code> diagram. It creates a node for the file using its source-relative label (falling back to the original key), then for each include it adds an <code>I</code> node with the include label and a directed edge from that node to the file node. Similarly, for each symbol it adds an <code>S</code> node with a short name obtained via <code>short_name_of_local</code> (or the raw name/qualified name as fallback) and an edge from the file node to the symbol node. All node labels are passed through <code>escape_mermaid_label</code>. The final Mermaid string is returned from the lambda, and <code>render_cached_diagram</code> handles caching of the result. Key dependencies include the diagram rendering infrastructure, the project model, configuration, and various utility functions for name shortening, path relativization, and Mermaid label escaping.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>plan<code>.owner_keys</code></li><li>config<code>.project_root</code></li><li>model<code>.files</code></li><li><code>file_it</code>-&gt;second<code>.includes</code></li><li><code>extract::SymbolInfo</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by page rendering pipeline for file pages</li><li>produces diagram code for file dependency visualization</li></ul><h3 id="clore-generate-render-import-diagram-code" tabindex="-1"><code>clore::generate::render_import_diagram_code</code> <a class="header-anchor" href="#clore-generate-render-import-diagram-code" aria-label="Permalink to &quot;`clore::generate::render_import_diagram_code`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:15</code></p><p>Definition: <code>generate/render/diagram.cppm:124</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The implementation of <code>clore::generate::render_import_diagram_code</code> first delegates to <code>render_cached_diagram</code>, which wraps the core logic for deduplication and caching. Inside the lambda, it immediately returns an empty string if <code>mod_unit.imports</code> is empty. It then computes <code>module_label</code> by extracting the top‑level module name via a local <code>top_module</code> lambda that truncates at the first colon; if <code>is_std_name</code> returns true for that label, the function again returns empty.</p><p>A deduplication pass collects unique import labels, skipping those equal to the current module or flagged as standard library names. After sorting the remaining imports, the function evaluates <code>should_emit_mermaid</code> with <code>node_count = 1 + imports.size()</code> and <code>edge_count = imports.size()</code>. If the check fails, an empty string is returned. Otherwise, it constructs a Mermaid graph string: a static node <code>M0</code> for the module, then for each import a node <code>I&lt;i&gt;</code> and a directed edge from that import node to <code>M0</code>. All labels are escaped using <code>escape_mermaid_label</code>. The final graph string is returned, and <code>render_cached_diagram</code> applies its caching layer.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>caches the generated Mermaid diagram result via <code>render_cached_diagram</code></li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>mod_unit.imports</code></li><li><code>mod_unit.name</code></li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>returns a <code>std::string</code> containing Mermaid diagram code</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called during module documentation generation to produce an import dependency diagram</li></ul><h3 id="clore-generate-render-module-dependency-diagram-code" tabindex="-1"><code>clore::generate::render_module_dependency_diagram_code</code> <a class="header-anchor" href="#clore-generate-render-module-dependency-diagram-code" aria-label="Permalink to &quot;`clore::generate::render_module_dependency_diagram_code`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:24</code></p><p>Definition: <code>generate/render/diagram.cppm:289</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The implementation of <code>clore::generate::render_module_dependency_diagram_code</code> constructs a Mermaid <code>graph LR</code> code string representing inter‑module dependencies. It begins by filtering the project model for interface module units, extracting the top‑level module name (everything before the first colon) for each unit. For each such module, it collects the set of modules it imports, excluding self‑references and any module flagged by <code>is_std_name</code>. These relations are stored in a <code>deps</code> map, and all referenced modules are tracked in a set. If fewer than two modules remain, the function returns an empty string. Next, it computes the total number of edges and calls <code>should_emit_mermaid</code> with the module and edge counts; if the diagram is not worth rendering, an empty string is returned again.</p><p>When emission is justified, the function sorts the module names alphabetically and assigns each a node identifier <code>M&lt;i&gt;</code> (e.g., <code>M0</code>, <code>M1</code>). It generates a <code>graph LR</code> header, then emits a node definition line for each module with an escaped label via <code>escape_mermaid_label</code>. Afterward, it iterates over the sorted module list in order, sorts each module’s dependency targets, and produces an edge line from the target node to the source node (arrow direction: <code>target --&gt; source</code>). The entire string is built and returned through <code>render_cached_diagram</code>, which provides memoization for the result. Key internal helpers used are <code>is_std_name</code>, <code>escape_mermaid_label</code>, <code>should_emit_mermaid</code>, and <code>render_cached_diagram</code>.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>model.modules</code></li><li><code>model.modules[name].is_interface</code></li><li><code>model.modules[name].name</code></li><li><code>model.modules[name].imports</code></li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value of type <code>std::string</code></li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to produce module dependency diagram for documentation pages</li><li>used within rendering pipeline to add Mermaid code blocks</li></ul><h3 id="clore-generate-render-namespace-diagram-code" tabindex="-1"><code>clore::generate::render_namespace_diagram_code</code> <a class="header-anchor" href="#clore-generate-render-namespace-diagram-code" aria-label="Permalink to &quot;`clore::generate::render_namespace_diagram_code`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:17</code></p><p>Definition: <code>generate/render/diagram.cppm:168</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function <code>clore::generate::render_namespace_diagram_code</code> first invokes <code>render_cached_diagram</code> with a lambda that encapsulates the diagram‑building logic. Inside the lambda, it looks up the given <code>namespace_name</code> in <code>model.namespaces</code>; if not found, it returns an empty string. For the found namespace, it iterates over <code>ns_it-&gt;second.symbols</code>, uses <code>extract::lookup_symbol</code> to retrieve each symbol, filters to type‑like kinds via <code>is_type_kind</code>, deduplicates by <code>SymbolID</code>, and stores the pointers in a vector. That vector is sorted by <code>qualified_name</code>. Next, it collects <code>ns_it-&gt;second.children</code>, filtering out any child string containing <code>&quot;(anonymous namespace)&quot;</code> or satisfying <code>is_std_name</code>, then transforms each with <code>short_name_of_local</code>. The child names are sorted and deduplicated. The total <code>edge_count</code> is <code>types.size() + children.size()</code> and <code>node_count</code> is <code>1 + edge_count</code>; if <code>should_emit_mermaid</code> returns <code>false</code>, an empty string is returned early. Otherwise, the function builds a Mermaid <code>graph TD</code> string: a node for the namespace itself (using <code>escape_mermaid_label</code> on its short name), then a node and edge for each type (prefixed <code>T</code> id), and similarly a node and edge for each child namespace (prefixed <code>NSC</code> id). The result is returned from the lambda and cached by <code>render_cached_diagram</code>.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>model<code>.namespaces</code></li><li>model<code>.symbols</code></li><li><code>ns_it</code>-&gt;second<code>.symbols</code></li><li><code>ns_it</code>-&gt;second<code>.children</code></li><li>types[i]-&gt;<code>qualified_name</code></li><li>children[i]</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called during namespace page generation to produce a Mermaid diagram</li></ul><h3 id="clore-generate-should-emit-mermaid" tabindex="-1"><code>clore::generate::should_emit_mermaid</code> <a class="header-anchor" href="#clore-generate-should-emit-mermaid" aria-label="Permalink to &quot;`clore::generate::should_emit_mermaid`&quot;">​</a></h3><p>Declaration: <code>generate/render/diagram.cppm:11</code></p><p>Definition: <code>generate/render/diagram.cppm:105</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/"><code>Namespace clore::generate</code></a></p><p>The function performs a simple threshold check: it returns <code>true</code> if either the <code>node_count</code> parameter meets or exceeds the constant <code>kMermaidMinNodes</code> or the <code>edge_count</code> parameter meets or exceeds the constant <code>kMermaidMinEdges</code>. Both constants are defined in the anonymous namespace and represent the minimum graph size (in nodes or edges) required to justify emitting a Mermaid diagram. The decision logic uses a short-circuiting logical OR; the caller can then skip rendering when the graph is too small to be useful.</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>local parameters <code>node_count</code> and <code>edge_count</code></li><li>constants <code>kMermaidMinNodes</code> and <code>kMermaidMinEdges</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called when deciding whether to render a Mermaid diagram in documentation pages</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>generate:diagram</code> module is organized around a small set of public rendering functions—<code>render_file_dependency_diagram_code</code>, <code>render_import_diagram_code</code>, <code>render_namespace_diagram_code</code>, and <code>render_module_dependency_diagram_code</code>—each returning an integer handle to the generated diagram text, plus <code>should_emit_mermaid</code> as a guard and <code>escape_mermaid_label</code> for label sanitization. Internally, the module decomposes work into several anonymous‑namespace helpers: <code>is_std_name</code>, <code>short_name_of_local</code>, <code>is_variable_kind_local</code>, <code>collect_implementation_symbols_for_diagram</code>, and a caching template <code>render_cached_diagram</code>. These helpers iterate over model objects (plans, configurations, symbol lists) to compute node and edge counts, construct labels, and produce Mermaid‑compatible output. The module depends on <code>generate:model</code> for its data structures, <code>extract</code> for symbol resolution, <code>support</code> for text and I/O utilities, and <code>config</code> for rendering options; thresholds like <code>kMermaidMinEdges</code> and <code>kMermaidMinNodes</code> control when diagrams are generated. State within each renderer is managed through local variables such as <code>node_id</code>, <code>edge_count</code>, <code>node_count</code>, <code>result</code>, <code>top_module</code>, <code>symbols</code>, and iteration indices, reflecting a straightforward traversal of the model graph without complex layering beyond the public‑helper split.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../extract/">Module extract</a></li><li><a href="./model">Module generate:model</a></li><li><a href="./../support/">Module support</a></li></ul>',80))])}const k=t(h,[["render",u]]);export{x as __pageData,k as default};
